const now = new Date();
const today = now.toISOString().slice(0, 10);
return [{
  json: {
    board_id: Number($env.NEXTCLOUD_DECK_BOARD_ID || 1919),
    source_stack_id: 5693,
    target_stack_vorbereitung: 5684,
    target_stack_freitagsagenda: 5687,
    label_ids: {
      review: 7898,
      action_required: 7901,
      information: 7907,
      diskussion: 7910,
      beschluss: 7913,
      sonstiges: 7916
    },
    today,
    generated_at: now.toISOString()
  }
}];

const cfg = $('Set Config').first().json;
const stacks = $input.all().map((item) => item.json || {});
const sourceStack = stacks.find((stack) => Number(stack.id || 0) === Number(cfg.source_stack_id));
function parseDateOnly(value) {
  const text = String(value || '').trim();
  if (!text) return '';
  const match = text.match(/\d{4}-\d{2}-\d{2}/);
  return match ? match[0] : '';
}
function extractField(description, fieldName) {
  const regex = new RegExp('^' + fieldName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\s*:\\s*(.*)$', 'mi');
  const match = String(description || '').match(regex);
  return match ? String(match[1] || '').trim() : '';
}
function replaceField(description, fieldName, newValue) {
  const regex = new RegExp('^' + fieldName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\s*:\\s*.*$', 'mi');
  if (regex.test(description)) return description.replace(regex, `${fieldName}: ${newValue}`);
  return description + `\n${fieldName}: ${newValue}`;
}
function parseTodos(description) {
  const lines = String(description || '').split(/\r?\n/);
  const todos = [];
  let current = null;
  let inTodoBlock = false;
  for (const rawLine of lines) {
    const trimmed = rawLine.trim();
    if (trimmed === 'ToDos') {
      inTodoBlock = true;
      continue;
    }
    if (!inTodoBlock) continue;
    const startMatch = trimmed.match(/^\d+\.\s+Aufgabe:\s*(.+)$/i);
    if (startMatch) {
      if (current) todos.push(current);
      current = { summary: String(startMatch[1] || '').trim(), owner: '', due_date: '', status: '' };
      continue;
    }
    if (!current) {
      if (/^(Technik|Sitzungsnotiz)\s*$/i.test(trimmed)) break;
      continue;
    }
    const ownerMatch = trimmed.match(/^Verantwortlich:\s*(.+)$/i);
    if (ownerMatch) { current.owner = String(ownerMatch[1] || '').trim(); continue; }
    const dueMatch = trimmed.match(/^Frist:\s*(.+)$/i);
    if (dueMatch) { current.due_date = parseDateOnly(dueMatch[1]); continue; }
    const statusMatch = trimmed.match(/^Status:\s*(.+)$/i);
    if (statusMatch) { current.status = String(statusMatch[1] || '').trim().toLowerCase(); continue; }
    if (/^(Technik|Sitzungsnotiz)\s*$/i.test(trimmed)) break;
  }
  if (current) todos.push(current);
  return todos;
}
function categoryToLabelId(category) {
  const normalized = String(category || '').trim().toLowerCase();
  if (normalized === 'information') return cfg.label_ids.information;
  if (normalized === 'diskussion') return cfg.label_ids.diskussion;
  if (normalized === 'beschluss') return cfg.label_ids.beschluss;
  return cfg.label_ids.sonstiges;
}
const cards = Array.isArray(sourceStack?.cards) ? sourceStack.cards : [];
const candidates = [];
for (const card of cards) {
  const description = String(card.description || '');
  const todos = parseTodos(description);
  const dueTodos = todos.filter((todo) => todo.due_date && String(todo.status || '').trim() !== 'erledigt' && todo.due_date <= cfg.today);
  const followupDate = parseDateOnly(extractField(description, 'Wiedervorlage/Frist'));
  const targetStatusRaw = extractField(description, 'Naechster Zielstatus');
  const wantsFriday = /freitagsagenda/i.test(targetStatusRaw);
  const isDueByFollowup = !!(followupDate && followupDate <= cfg.today);
  if (!dueTodos.length && !isDueByFollowup) continue;
  const targetStackId = wantsFriday ? cfg.target_stack_freitagsagenda : cfg.target_stack_vorbereitung;
  const targetStatus = wantsFriday ? 'Freitagsagenda' : 'Vorbereitung';
  const updatedDescription = [
    replaceField(description, 'Status', targetStatus),
    '',
    'Automation',
    `reagenda_from_card_id: ${card.id}`,
    `reagenda_at: ${cfg.generated_at}`,
    `reagenda_reason: ${dueTodos.length ? 'todo_due' : 'followup_due'}`
  ].join('\n').replace(/\n{3,}/g, '\n\n');
  const labels = Array.isArray(card.labels) ? card.labels : [];
  const hasReview = labels.some((label) => Number(label.id || 0) === cfg.label_ids.review);
  candidates.push({
    source_card_id: Number(card.id || 0),
    source_stack_id: Number(cfg.source_stack_id),
    target_stack_id: targetStackId,
    target_status: targetStatus,
    title: String(card.title || '').trim() || 'Ohne Titel',
    description: updatedDescription,
    category: extractField(description, 'Kategorie') || 'Sonstiges',
    category_label_id: categoryToLabelId(extractField(description, 'Kategorie') || 'Sonstiges'),
    preserve_review_label: hasReview,
    due_todos: dueTodos,
    followup_date: followupDate,
    source_labels: labels.map((label) => ({ id: Number(label.id || 0), title: String(label.title || '').trim() }))
  });
}
return candidates.map((candidate) => ({ json: candidate }));

const created = $input.first().json || {};
const original = $('Split Candidates').item.json || {};
return [{ json: { ...original, target_card_id: Number(created.id || 0) } }];

const item = $input.first().json || {};
return [{
  json: {
    result: 'reagenda_recreated',
    source_card_id: item.source_card_id,
    target_card_id: item.target_card_id,
    target_stack_id: item.target_stack_id,
    target_status: item.target_status,
    title: item.title,
    followup_date: item.followup_date,
    due_todo_count: Array.isArray(item.due_todos) ? item.due_todos.length : 0
  }
}];
